{
  "name": "SupaGuard Pro",
  "description": "A high-performance dashboard for managing Supabase projects, visualizing database status, and monitoring backups via the Supabase Management API.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Organization {
  id: string;
  name: string;
}

export interface Project {
  id: string;
  organization_id: string;
  name: string;
  region: string;
  created_at: string;
  status: 'ACTIVE_HEALTHY' | 'RESTORING' | 'INIT_FAILED' | 'PAUSED';
}

export interface Backup {
  id: string;
  project_id: string;
  inserted_at: string;
  is_physical: boolean;
  status: string;
}

export interface AppState {
  token: string | null;
  organizations: Organization[];
  projects: Project[];
  selectedProject: Project | null;
  backups: Backup[];
  loading: boolean;
  error: string | null;
}

import { Organization, Project, Backup } from '../types';

const BASE_URL = 'https://api.supabase.com/v1';

export const supabaseApi = {
  getOrganizations: async (token: string): Promise<Organization[]> => {
    const res = await fetch(`${BASE_URL}/organizations`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) throw new Error('Failed to fetch organizations');
    return res.json();
  },

  getProjects: async (token: string): Promise<Project[]> => {
    const res = await fetch(`${BASE_URL}/projects`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) throw new Error('Failed to fetch projects');
    return res.json();
  },

  getBackups: async (token: string, projectRef: string): Promise<Backup[]> => {
    const res = await fetch(`${BASE_URL}/projects/${projectRef}/backups`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    // Some projects might not have backup access depending on plan
    if (!res.ok) return [];
    return res.json();
  },
};

import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AppState, Project, Organization, Backup } from './types';
import { supabaseApi } from './services/supabaseService';
import { Layout } from './components/Layout';
import { ProjectCard } from './components/ProjectCard';
import { BackupList } from './components/BackupList';
import { TokenInput } from './components/TokenInput';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    token: localStorage.getItem('sb_token'),
    organizations: [],
    projects: [],
    selectedProject: null,
    backups: [],
    loading: false,
    error: null,
  });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [analyzing, setAnalyzing] = useState(false);

  const fetchData = useCallback(async (token: string) => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const [orgs, projs] = await Promise.all([
        supabaseApi.getOrganizations(token),
        supabaseApi.getProjects(token),
      ]);
      setState(prev => ({
        ...prev,
        organizations: orgs,
        projects: projs,
        loading: false,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Unknown error',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token);
    }
  }, [state.token, fetchData]);

  const handleSetToken = (token: string) => {
    localStorage.setItem('sb_token', token);
    setState(prev => ({ ...prev, token }));
  };

  const handleLogout = () => {
    localStorage.removeItem('sb_token');
    setState({
      token: null,
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      loading: false,
      error: null,
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true }));
    try {
      const backups = await supabaseApi.getBackups(state.token, project.id);
      setState(prev => ({ ...prev, backups, loading: false }));

      // AI Insight logic
      generateAiInsight(project);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const generateAiInsight = async (project: Project) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `Como um engenheiro de banco de dados sênior, analise este projeto Supabase e sugira uma estratégia de backup e segurança.
      Nome: ${project.name}
      Região: ${project.region}
      Status: ${project.status}
      ID: ${project.id}
      Crie um resumo curto (3-4 frases) em Português sobre os riscos e as melhores práticas recomendadas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Nenhuma análise disponível.');
    } catch (error) {
      setAiAnalysis('Ocorreu um erro ao gerar insights da IA.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-8">
        <header className="mb-8">
          <h1 className="text-3xl font-bold text-white mb-2">Painel de Gerenciamento</h1>
          <p className="text-gray-400">Gerencie seus projetos e monitore a integridade dos dados.</p>
        </header>

        {state.error && (
          <div className="bg-red-900/30 border border-red-500 text-red-200 p-4 rounded-lg mb-8">
            <p className="font-semibold">Erro: {state.error}</p>
            <button 
              onClick={() => fetchData(state.token!)}
              className="text-sm underline mt-2 hover:text-red-100"
            >
              Tentar novamente
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-4">
            <h2 className="text-xl font-semibold text-white flex items-center gap-2">
              <svg className="w-5 h-5 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
              </svg>
              Projetos ({state.projects.length})
            </h2>
            <div className="space-y-3">
              {state.projects.map(p => (
                <ProjectCard 
                  key={p.id} 
                  project={p} 
                  isSelected={state.selectedProject?.id === p.id}
                  onClick={() => handleSelectProject(p)}
                />
              ))}
            </div>
          </div>

          <div className="lg:col-span-2 space-y-8">
            {state.selectedProject ? (
              <>
                <div className="glass-card rounded-xl p-6">
                  <div className="flex justify-between items-start mb-6">
                    <div>
                      <h2 className="text-2xl font-bold text-white mb-1">{state.selectedProject.name}</h2>
                      <p className="text-gray-400 text-sm">Ref: {state.selectedProject.id}</p>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                      state.selectedProject.status === 'ACTIVE_HEALTHY' ? 'bg-emerald-900/50 text-emerald-400 border border-emerald-500' : 'bg-yellow-900/50 text-yellow-400 border border-yellow-500'
                    }`}>
                      {state.selectedProject.status}
                    </span>
                  </div>

                  <div className="grid grid-cols-2 gap-4 mb-6">
                    <div className="bg-gray-800/50 p-4 rounded-lg">
                      <p className="text-gray-500 text-xs uppercase tracking-wider mb-1">Região</p>
                      <p className="text-white font-medium">{state.selectedProject.region}</p>
                    </div>
                    <div className="bg-gray-800/50 p-4 rounded-lg">
                      <p className="text-gray-500 text-xs uppercase tracking-wider mb-1">Criado em</p>
                      <p className="text-white font-medium">{new Date(state.selectedProject.created_at).toLocaleDateString()}</p>
                    </div>
                  </div>

                  <div className="border-t border-gray-800 pt-6">
                    <h3 className="text-emerald-400 font-semibold mb-3 flex items-center gap-2">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                      </svg>
                      Insight da IA (Segurança & Backups)
                    </h3>
                    <div className="bg-emerald-950/20 border border-emerald-900/50 p-4 rounded-lg text-gray-300 italic min-h-[80px]">
                      {analyzing ? (
                        <div className="flex items-center gap-3">
                          <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-emerald-500"></div>
                          <span>Analisando infraestrutura...</span>
                        </div>
                      ) : (
                        <p>{aiAnalysis || "Selecione um projeto para ver insights."}</p>
                      )}
                    </div>
                  </div>
                </div>

                <BackupList backups={state.backups} />
              </>
            ) : (
              <div className="glass-card rounded-xl p-12 text-center flex flex-col items-center justify-center min-h-[400px]">
                <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mb-4">
                  <svg className="w-8 h-8 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                </div>
                <h3 className="text-xl font-medium text-white mb-2">Nenhum projeto selecionado</h3>
                <p className="text-gray-500 max-w-xs">Selecione um projeto na lista lateral para visualizar detalhes e backups.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default App;

