              className="w-full bg-gray-900 border border-gray-800 text-white px-4 py-3 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all placeholder:text-gray-700"
            />
          </div>

          <button
            type="submit"
            className="w-full supabase-gradient hover:opacity-90 text-white font-bold py-3 rounded-xl shadow-lg transition-all active:scale-[0.98]"
