export interface Organization {
  id: string;
  name: string;
}

export interface Project {
  id: string;
  organization_id: string;
  name: string;
  region: string;
  created_at: string;
  status: 'ACTIVE_HEALTHY' | 'RESTORING' | 'INIT_FAILED' | 'PAUSED';
}

export interface Backup {
  id: string;
  project_id: string;
  inserted_at: string;
  is_physical: boolean;
  status: string;
}

export interface TableColumn {
  name: string;
  format: string;
  data_type: string;
  is_nullable: boolean;
  is_identity: boolean;
}

export interface Table {
  id: number;
  name: string;
  schema: string;
  columns?: TableColumn[];
}

export interface AppState {
  token: string | null;
  organizations: Organization[];
  projects: Project[];
  selectedProject: Project | null;
  backups: Backup[];
  tables: Table[];
  loading: boolean;
  error: string | null;
  activeView: 'dashboard' | 'explorer';
}

import { Organization, Project, Backup, Table } from '../types';

const BASE_URL = 'https://api.supabase.com/v1';

export const supabaseApi = {
  getOrganizations: async (token: string): Promise<Organization[]> => {
    const res = await fetch(`${BASE_URL}/organizations`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) throw new Error('Failed to fetch organizations');
    return res.json();
  },

  getProjects: async (token: string): Promise<Project[]> => {
    const res = await fetch(`${BASE_URL}/projects`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) throw new Error('Failed to fetch projects');
    return res.json();
  },

  getBackups: async (token: string, projectRef: string): Promise<Backup[]> => {
    const res = await fetch(`${BASE_URL}/projects/${projectRef}/backups`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) return [];
    return res.json();
  },

  getTables: async (token: string, projectRef: string): Promise<Table[]> => {
    // Note: The Management API provides database structure info
    const res = await fetch(`${BASE_URL}/projects/${projectRef}/database/tables`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) throw new Error('Failed to fetch tables. Verify your permissions.');
    return res.json();
  },

  triggerBackup: async (token: string, projectRef: string): Promise<void> => {
    // Most Supabase backups are scheduled. This simulates a request to the management system
    // for a physical backup point (often used in PITR enabled projects).
    return new Promise((resolve) => setTimeout(resolve, 2000));
  }
};

import React, { useState } from 'react';
import { Table, TableColumn } from '../types';

interface TableExplorerProps {
  tables: Table[];
  loading: boolean;
}

export const TableExplorer: React.FC<TableExplorerProps> = ({ tables, loading }) => {
  const [selectedTableId, setSelectedTableId] = useState<number | null>(null);

  const selectedTable = tables.find(t => t.id === selectedTableId);

  if (loading && tables.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-gray-500">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-emerald-500 mb-4"></div>
        <p>Carregando estrutura do banco de dados...</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
      <div className="md:col-span-1 space-y-2">
        <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-4 px-2">Tabelas ({tables.length})</h3>
        <div className="max-h-[600px] overflow-y-auto space-y-1 pr-2">
          {tables.map(table => (
            <button
              key={table.id}
              onClick={() => setSelectedTableId(table.id)}
              className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-colors flex items-center gap-2 ${
                selectedTableId === table.id 
                  ? 'bg-emerald-900/30 text-emerald-400 border border-emerald-500/30' 
                  : 'text-gray-400 hover:bg-gray-800 hover:text-white'
              }`}
            >
              <svg className="w-4 h-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
              <span className="truncate">{table.name}</span>
            </button>
          ))}
        </div>
      </div>

      <div className="md:col-span-3">
        {selectedTable ? (
          <div className="glass-card rounded-xl overflow-hidden border border-gray-800">
            <div className="bg-gray-800/50 px-6 py-4 flex items-center justify-between border-b border-gray-800">
              <div>
                <h3 className="text-xl font-bold text-white">{selectedTable.name}</h3>
                <p className="text-xs text-emerald-500 font-mono">Schema: {selectedTable.schema}</p>
              </div>
              <div className="flex gap-2">
                <span className="bg-gray-900 text-gray-500 px-2 py-1 rounded text-[10px] font-bold border border-gray-800">
                  {selectedTable.columns?.length || 0} COLUNAS
                </span>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-900 text-xs text-gray-500 uppercase font-mono">
                  <tr>
                    <th className="px-6 py-3">Nome da Coluna</th>
                    <th className="px-6 py-3">Tipo de Dado</th>
                    <th className="px-6 py-3">Formato</th>
                    <th className="px-6 py-3">Nullable</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-800/50">
                  {selectedTable.columns?.map((col, idx) => (
                    <tr key={idx} className="hover:bg-emerald-500/5 transition-colors">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <span className="text-white font-medium">{col.name}</span>
                          {col.is_identity && (
                            <span className="text-[9px] bg-emerald-900/50 text-emerald-400 px-1 rounded border border-emerald-500/30">PK</span>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-400">{col.data_type}</td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-500">{col.format}</td>
                      <td className="px-6 py-4">
                        <span className={`text-xs ${col.is_nullable ? 'text-gray-600' : 'text-emerald-500 font-bold'}`}>
                          {col.is_nullable ? 'YES' : 'NO'}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          <div className="glass-card rounded-xl p-12 text-center flex flex-col items-center justify-center border-dashed border-2 border-gray-800">
            <svg className="w-12 h-12 text-gray-700 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
