    loading: false,
    error: null,
    activeView: 'dashboard',
  });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [analyzing, setAnalyzing] = useState(false);

  const fetchData = useCallback(async (token: string) => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const [orgs, projs] = await Promise.all([
        supabaseApi.getOrganizations(token),
        supabaseApi.getProjects(token),
      ]);
      setState(prev => ({
        ...prev,
        organizations: orgs,
        projects: projs,
        loading: false,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Erro na conexão com Supabase',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token);
    }
  }, [state.token, fetchData]);

  const handleSetToken = (token: string) => {
    localStorage.setItem('sb_token', token);
    setState(prev => ({ ...prev, token }));
