  const handleLogout = () => {
    localStorage.removeItem('sb_token');
    setState({
      token: null,
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      tables: [],
      loading: false,
      error: null,
      activeView: 'dashboard',
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true, tables: [], backups: [] }));
    try {
      const [backups, tables] = await Promise.all([
        supabaseApi.getBackups(state.token, project.id),
        supabaseApi.getTables(state.token, project.id),
      ]);
      setState(prev => ({ ...prev, backups, tables, loading: false }));
      generateAiInsight(project);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const handleTriggerBackup = async () => {
    if (!state.token || !state.selectedProject) return;
    try {
      await supabaseApi.triggerBackup(state.token, state.selectedProject.id);
      // Refresh backup list
      const backups = await supabaseApi.getBackups(state.token, state.selectedProject.id);
      setState(prev => ({ ...prev, backups }));
    } catch (err) {
      alert("Erro ao solicitar backup. Verifique as permissões do seu token.");
    }
  };

  const generateAiInsight = async (project: Project) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `Como um engenheiro de banco de dados sênior, analise este projeto Supabase e sugira uma estratégia de backup e segurança.
