        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Nenhuma análise disponível.');
    } catch (error) {
      setAiAnalysis('Insight indisponível no momento.');
    } finally {
      setAnalyzing(false);
    }
  };

