            >
              Dashboard
            </button>
            <button
              onClick={() => setState(prev => ({...prev, activeView: 'explorer'}))}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${state.activeView === 'explorer' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
            >
