import { Organization, Project, Backup, Table } from '../types';

const BASE_URL = 'https://api.supabase.com/v1';

const handleResponse = async (res: Response, context: string) => {
  if (res.ok) return res.json();

  if (res.status === 401) throw new Error(`Não autorizado (401): Seu token é inválido ou expirou.`);
  if (res.status === 403) throw new Error(`Acesso Negado (403): O token não tem permissões suficientes para ${context}.`);
  if (res.status === 429) throw new Error(`Limite atingido (429): Muitas requisições. Tente novamente em breve.`);

  const errorData = await res.json().catch(() => ({}));
  throw new Error(`${context} falhou (${res.status}): ${errorData.message || res.statusText}`);
};

export const supabaseApi = {
  getOrganizations: async (token: string): Promise<Organization[]> => {
    try {
      const res = await fetch(`${BASE_URL}/organizations`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      return handleResponse(res, 'Buscar organizações');
    } catch (err) {
      if (err instanceof TypeError && err.message === 'Failed to fetch') {
        throw new Error('Erro de Conexão (CORS/Network): O navegador bloqueou a requisição. Verifique sua internet ou permissões de API.');
      }
      throw err;
    }
  },

  getProjects: async (token: string): Promise<Project[]> => {
    try {
      const res = await fetch(`${BASE_URL}/projects`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      return handleResponse(res, 'Listar projetos');
    } catch (err) {
      if (err instanceof TypeError && err.message === 'Failed to fetch') {
        throw new Error('Erro de Rede: Não foi possível conectar à API do Supabase.');
      }
      throw err;
    }
  },

  getBackups: async (token: string, projectRef: string): Promise<Backup[]> => {
    const res = await fetch(`${BASE_URL}/projects/${projectRef}/backups`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) return [];
    return res.json();
  },

  getTables: async (token: string, projectRef: string): Promise<Table[]> => {
    const res = await fetch(`${BASE_URL}/projects/${projectRef}/database/tables`, {
      headers: { Authorization: `Bearer ${token}` },
    });
    if (!res.ok) return [];
    return res.json();
  },

  triggerBackup: async (token: string, projectRef: string): Promise<void> => {
    // Simulação de trigger pois a API de backup físico é restrita a planos Enterprise/PITR
    return new Promise((resolve) => setTimeout(resolve, 2000));
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AppState, Project, Organization, Backup, Table } from './types';
