import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AppState, Project, Organization, Backup, Table } from './types';
import { supabaseApi } from './services/supabaseService';
import { Layout } from './components/Layout';
import { ProjectCard } from './components/ProjectCard';
import { BackupList } from './components/BackupList';
import { TokenInput } from './components/TokenInput';
import { TableExplorer } from './components/TableExplorer';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    token: localStorage.getItem('sb_token'),
    proxyUrl: localStorage.getItem('sb_proxy') || '',
    organizations: [],
    projects: [],
    selectedProject: null,
    backups: [],
    tables: [],
    loading: false,
    error: null,
    activeView: 'dashboard',
  });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [analyzing, setAnalyzing] = useState(false);

  const fetchData = useCallback(async (token: string, proxy: string) => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const [orgs, projs] = await Promise.all([
        supabaseApi.getOrganizations(token, proxy),
        supabaseApi.getProjects(token, proxy),
      ]);
      setState(prev => ({
        ...prev,
        organizations: orgs,
        projects: projs,
        loading: false,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Erro crítico na conexão',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token, state.proxyUrl);
    }
  }, [state.token, state.proxyUrl, fetchData]);

  const handleSetToken = (token: string, proxy: string) => {
    localStorage.setItem('sb_token', token);
    localStorage.setItem('sb_proxy', proxy);
    setState(prev => ({ ...prev, token, proxyUrl: proxy }));
  };

  const handleLogout = () => {
    localStorage.removeItem('sb_token');
    localStorage.removeItem('sb_proxy');
    setState({
      token: null,
      proxyUrl: '',
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      tables: [],
      loading: false,
      error: null,
      activeView: 'dashboard',
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true, tables: [], backups: [] }));
    try {
      const [backups, tables] = await Promise.all([
        supabaseApi.getBackups(state.token, project.id, state.proxyUrl),
        supabaseApi.getTables(state.token, project.id, state.proxyUrl),
      ]);
      setState(prev => ({ ...prev, backups, tables, loading: false }));
      generateAiInsight(project);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const handleTriggerBackup = async () => {
    if (!state.token || !state.selectedProject) return;
    try {
      await supabaseApi.triggerBackup(state.token, state.selectedProject.id);
      const backups = await supabaseApi.getBackups(state.token, state.selectedProject.id, state.proxyUrl);
      setState(prev => ({ ...prev, backups }));
    } catch (err) {
      alert("Falha ao iniciar backup.");
    }
  };

  const generateAiInsight = async (project: Project) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `Analise este projeto Supabase e sugira boas práticas de backup:
      Nome: ${project.name} | Região: ${project.region}
      Responda em Português (2 frases).`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Insight indisponível.');
    } catch (error) {
      setAiAnalysis('Insight indisponível.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-8">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-white mb-2 tracking-tight">Gestão de Infraestrutura</h1>
            <p className="text-gray-400">Status da conexão: <span className={state.error ? 'text-red-500' : 'text-emerald-500'}>{state.error ? 'Erro de Rede' : 'Conectado'}</span></p>
          </div>

          <div className="flex bg-gray-900/50 p-1 rounded-xl border border-gray-800 self-start">
            <button
              onClick={() => setState(prev => ({...prev, activeView: 'dashboard'}))}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${state.activeView === 'dashboard' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'text-gray-400 hover:text-white'}`}
            >
              Dashboard
            </button>
            <button
              onClick={() => setState(prev => ({...prev, activeView: 'explorer'}))}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${state.activeView === 'explorer' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'text-gray-400 hover:text-white'}`}
            >
              Explorador
            </button>
          </div>
        </header>

        {state.error && (
          <div className="bg-red-500/10 border border-red-500/50 p-6 rounded-2xl mb-8 animate-in fade-in zoom-in duration-300">
            <div className="flex items-start gap-4">
              <div className="bg-red-500/20 p-2 rounded-lg text-red-500">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
              <div className="flex-grow">
                <h3 className="text-lg font-bold text-red-200">Bloqueio de CORS Detectado</h3>
                <p className="text-red-400/80 text-sm mb-4">{state.error}</p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="bg-gray-900/50 rounded-xl p-4 border border-red-500/20">
                    <p className="text-[10px] font-bold text-gray-500 uppercase mb-2">Opção A (Mais fácil)</p>
                    <p className="text-xs text-gray-400">Instale a extensão de navegador <strong>"Allow CORS"</strong> e ative-a para este site.</p>
                  </div>
                  <div className="bg-gray-900/50 rounded-xl p-4 border border-red-500/20">
                    <p className="text-[10px] font-bold text-gray-500 uppercase mb-2">Opção B (Proxy)</p>
                    <p className="text-xs text-gray-400">Clique em "Trocar Token" e configure uma URL de Proxy (ex: cors-anywhere).</p>
                  </div>
                </div>

                <div className="mt-4 flex gap-3">
                  <button onClick={() => fetchData(state.token!, state.proxyUrl)} className="bg-red-500 text-white text-xs font-bold py-2 px-4 rounded-lg">TENTAR NOVAMENTE</button>
                  <button onClick={handleLogout} className="border border-red-500/30 text-red-400 text-xs font-bold py-2 px-4 rounded-lg">TROCAR CONFIGURAÇÕES</button>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
