import { TokenInput } from './components/TokenInput';
import { TableExplorer } from './components/TableExplorer';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    try {
      return {
        token: localStorage.getItem('sb_token'),
        proxyUrl: localStorage.getItem('sb_proxy') || 'https://cors-anywhere.herokuapp.com/',
        organizations: [],
        projects: [],
        selectedProject: null,
        backups: [],
        tables: [],
        loading: false,
        error: null,
        activeView: 'dashboard',
      };
    } catch {
      return {
        token: null,
        proxyUrl: 'https://cors-anywhere.herokuapp.com/',
        organizations: [],
        projects: [],
        selectedProject: null,
        backups: [],
        tables: [],
        loading: false,
        error: null,
        activeView: 'dashboard',
      };
    }
  });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [analyzing, setAnalyzing] = useState(false);

  const fetchData = useCallback(async (token: string, proxy: string) => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const [orgs, projs] = await Promise.all([
        supabaseApi.getOrganizations(token, proxy),
        supabaseApi.getProjects(token, proxy),
      ]);
      setState(prev => ({
        ...prev,
        organizations: orgs || [],
        projects: projs || [],
        loading: false,
      }));
    } catch (err) {
      console.error('Fetch error in App:', err);
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Falha na conexão com a API',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token, state.proxyUrl);
    }
  }, [state.token, state.proxyUrl, fetchData]);

  const handleSetToken = (token: string, proxy: string) => {
    try {
      localStorage.setItem('sb_token', token);
      localStorage.setItem('sb_proxy', proxy);
    } catch (e) {}
    setState(prev => ({ ...prev, token, proxyUrl: proxy }));
  };

  const handleLogout = () => {
    try {
      localStorage.removeItem('sb_token');
      localStorage.removeItem('sb_proxy');
    } catch (e) {}
    setState({
      token: null,
      proxyUrl: 'https://cors-anywhere.herokuapp.com/',
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      tables: [],
      loading: false,
      error: null,
      activeView: 'dashboard',
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true, tables: [], backups: [] }));
    try {
      const [backups, tables] = await Promise.all([
        supabaseApi.getBackups(state.token, project.id, state.proxyUrl),
        supabaseApi.getTables(state.token, project.id, state.proxyUrl),
      ]);
      setState(prev => ({ ...prev, backups, tables, loading: false }));
      generateAiInsight(project);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const handleTriggerBackup = async () => {
    if (!state.token || !state.selectedProject) return;
    try {
      await supabaseApi.triggerBackup(state.token, state.selectedProject.id, state.proxyUrl);
      const backups = await supabaseApi.getBackups(state.token, state.selectedProject.id, state.proxyUrl);
      setState(prev => ({ ...prev, backups }));
    } catch (err) {
      alert("Falha ao iniciar backup. Certifique-se de que seu plano permite backups físicos.");
    }
  };

  const generateAiInsight = async (project: Project) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `Como um especialista em infraestrutura, sugira rapidamente uma prática de segurança ou backup para um banco Supabase na região ${project.region}. Responda em Português em 2 frases curtas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Insight indisponível no momento.');
    } catch (error) {
      setAiAnalysis('Gemini AI está fora de alcance.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-6 md:py-8">
        <header className="mb-6 flex flex-col gap-4">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold text-white mb-1 tracking-tight">Painel de Controle</h1>
              <p className="text-xs text-gray-500 uppercase tracking-widest font-semibold">
                Monitoramento: <span className={state.error ? 'text-red-500' : 'text-emerald-500'}>{state.error ? 'Inativo' : 'Ativo'}</span>
              </p>
            </div>

            <div className="flex bg-gray-900/80 p-1 rounded-xl border border-gray-800 w-full md:w-auto">
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'dashboard'}))}
                className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${state.activeView === 'dashboard' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'text-gray-500 hover:text-white'}`}
              >
                Geral
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'explorer'}))}
                className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${state.activeView === 'explorer' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'text-gray-500 hover:text-white'}`}
              >
                Banco
              </button>
            </div>
          </div>
        </header>

        {state.error && (
          <div className="bg-red-500/10 border border-red-500/30 p-5 rounded-2xl mb-8 animate-in fade-in zoom-in duration-300">
            <div className="flex flex-col md:flex-row items-center gap-4 text-center md:text-left">
              <div className="bg-red-500/20 p-3 rounded-full text-red-500">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <div className="flex-grow">
                <h3 className="text-sm font-bold text-red-200 uppercase tracking-widest">Erro de Conectividade</h3>
                <p className="text-red-400/80 text-xs mb-3">{state.error}</p>
                <div className="flex flex-wrap gap-2 justify-center md:justify-start">
                  <button onClick={() => fetchData(state.token!, state.proxyUrl)} className="bg-red-500/20 hover:bg-red-500/40 text-red-200 text-[10px] font-bold py-2 px-4 rounded-lg border border-red-500/30 uppercase">Recarregar</button>
                  <button onClick={handleLogout} className="bg-gray-800 text-gray-300 text-[10px] font-bold py-2 px-4 rounded-lg border border-gray-700 uppercase">Trocar Configurações</button>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          <aside className="lg:col-span-1 space-y-4">
            <h2 className="text-[10px] font-bold text-gray-600 uppercase tracking-[0.2em] px-2">Projetos Ativos</h2>
            {state.projects.length > 0 ? (
              <div className="space-y-2">
                {state.projects.map(p => (
                  <ProjectCard 
                    key={p.id} 
                    project={p} 
                    isSelected={state.selectedProject?.id === p.id}
                    onClick={() => handleSelectProject(p)}
                  />
                ))}
              </div>
            ) : !state.loading && (
              <div className="p-10 border-2 border-dashed border-gray-800 rounded-2xl text-center">
                <p className="text-xs text-gray-600 italic">Nenhum projeto encontrado.</p>
              </div>
            )}
          </aside>

          <section className="lg:col-span-3">
            {state.selectedProject ? (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {state.activeView === 'dashboard' ? (
                  <>
                    <div className="glass-card rounded-2xl p-6 md:p-8 border border-gray-800 relative overflow-hidden">
                      <div className="flex flex-col md:flex-row justify-between items-start gap-4 mb-6">
                        <div>
                          <h2 className="text-2xl font-bold text-white mb-1">{state.selectedProject.name}</h2>
                          <div className="flex items-center gap-2">
                             <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                             <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest font-mono">{state.selectedProject.id}</span>
                          </div>
                        </div>
                        <span className="text-[10px] bg-emerald-900/30 text-emerald-400 px-3 py-1.5 rounded-full border border-emerald-500/30 font-bold uppercase tracking-widest">{state.selectedProject.status}</span>
                      </div>

                      <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-8">
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Região</p>
                          <p className="text-sm text-white font-medium">{state.selectedProject.region}</p>
                        </div>
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Tabelas</p>
                          <p className="text-sm text-white font-medium">{state.tables.length}</p>
                        </div>
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800 col-span-2 md:col-span-1">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Último Snapshot</p>
                          <p className="text-sm text-white font-medium">{state.backups.length > 0 ? new Date(state.backups[0].inserted_at).toLocaleDateString() : 'Sem dados'}</p>
                        </div>
                      </div>

                      <div className="border-t border-gray-800/50 pt-6">
                        <div className="flex items-center gap-2 mb-3">
                          <div className="w-5 h-5 bg-emerald-500/10 rounded-md flex items-center justify-center">
                            <svg className="w-3 h-3 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                            </svg>
                          </div>
                          <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest">Insight AI</h3>
                        </div>
                        <div className="bg-emerald-500/5 border border-emerald-500/10 p-4 rounded-xl">
                          {analyzing ? (
                            <div className="flex items-center gap-2 text-emerald-500 text-xs">
                              <div className="animate-spin rounded-full h-3 w-3 border-b-2 border-emerald-500"></div>
                              <span>Consultando especialista...</span>
                            </div>
                          ) : (
                            <p className="text-gray-300 text-sm italic leading-relaxed">
                              {aiAnalysis || "Aguardando carregamento de dados para análise..."}
                            </p>
                          )}
                        </div>
                      </div>
                    </div>

                    <BackupList backups={state.backups} onTriggerBackup={handleTriggerBackup} />
                  </>
                ) : (
                  <TableExplorer tables={state.tables} loading={state.loading} />
                )}
              </div>
            ) : (
              <div className="glass-card rounded-2xl p-16 text-center flex flex-col items-center justify-center min-h-[400px] border-dashed border-2 border-gray-800">
                <div className="w-16 h-16 bg-gray-900 rounded-3xl flex items-center justify-center mb-6 text-gray-700">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M8 9l3 3-3 3m5 0h3M5 20h14a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
                <h3 className="text-xl font-bold text-white mb-2">Selecione um Projeto</h3>
                <p className="text-gray-500 text-sm max-w-xs mx-auto">
                  Clique em um projeto à esquerda para visualizar estatísticas, gerenciar backups e explorar tabelas.
                </p>
              </div>
            )}
          </section>
        </div>
      </div>
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Backup } from '../types';

interface BackupListProps {
  backups: Backup[];
  onTriggerBackup: () => Promise<void>;
}

export const BackupList: React.FC<BackupListProps> = ({ backups, onTriggerBackup }) => {
  const [requesting, setRequesting] = useState(false);

  const handleTrigger = async () => {
    setRequesting(true);
    try {
      await onTriggerBackup();
    } finally {
      setRequesting(false);
    }
  };

  const handleDownloadInfo = (backup: Backup) => {
    const info = {
      project_id: backup.project_id,
      backup_id: backup.id,
      timestamp: backup.inserted_at,
      type: backup.is_physical ? 'Physical' : 'Logical',
      status: backup.status,
      instruction: "Backups físicos são gerenciados pela infraestrutura Supabase. Para download do arquivo bruto (SQL Dump), utilize o Supabase CLI ou a aba 'Exportar' no Table Explorer."
    };

    const blob = new Blob([JSON.stringify(info, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `backup-info-${backup.id.substring(0, 8)}.json`;
    a.click();
    URL.revokeObjectURL(url);

    alert("ℹ️ Nota: Este arquivo contém os metadados do snapshot. Backups físicos (Physical) são restaurados via painel oficial. Para baixar dados das tabelas, use a aba 'Banco' -> 'Exportar Estrutura'.");
  };

  return (
    <div className="glass-card rounded-xl overflow-hidden animate-in fade-in duration-500">
      <div className="px-6 py-5 border-b border-gray-800 flex flex-col sm:flex-row sm:items-center justify-between bg-gray-900/20 gap-4">
        <div>
          <h3 className="font-bold text-white text-lg">Snapshots de Infraestrutura</h3>
          <p className="text-xs text-gray-500 mt-1">Pontos de restauração gerenciados pelo Supabase.</p>
        </div>
        <button 
          onClick={handleTrigger}
          disabled={requesting}
          className={`text-xs font-bold px-5 py-2.5 rounded-xl border transition-all flex items-center justify-center gap-2 ${
            requesting 
              ? 'bg-gray-800 text-gray-500 border-gray-700 cursor-not-allowed'
              : 'bg-emerald-500 text-white border-emerald-400 hover:brightness-110 shadow-lg shadow-emerald-500/10'
          }`}
        >
          {requesting ? (
            <div className="animate-spin rounded-full h-3 w-3 border-b-2 border-white"></div>
          ) : (
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          )}
          {requesting ? 'Solicitando...' : 'Criar Novo Snapshot'}
        </button>
      </div>

      {backups.length === 0 ? (
        <div className="p-16 text-center">
          <div className="w-12 h-12 bg-gray-800/50 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg className="w-6 h-6 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
            </svg>
          </div>
          <p className="text-gray-500 text-sm max-w-xs mx-auto italic">Nenhum backup físico detectado. Isso é comum em planos gratuitos ou novos projetos.</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-800/40 text-[10px] text-gray-400 uppercase tracking-widest font-bold">
              <tr>
                <th className="px-6 py-4">Data e Hora</th>
                <th className="px-6 py-4">Tipo</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Metadados</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-800/50">
              {backups.map((b) => (
                <tr key={b.id} className="text-sm hover:bg-emerald-500/5 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-white font-medium">{new Date(b.inserted_at).toLocaleDateString()}</span>
                      <span className="text-[10px] text-gray-500 font-mono">{new Date(b.inserted_at).toLocaleTimeString()}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-0.5 rounded text-[9px] font-black border uppercase tracking-tighter ${
                      b.is_physical 
                        ? 'bg-blue-900/20 text-blue-400 border-blue-500/30' 
                        : 'bg-purple-900/20 text-purple-400 border-purple-500/30'
                    }`}>
                      {b.is_physical ? 'Physical' : 'Logical'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-[10px] font-bold bg-emerald-950/30 text-emerald-500 border border-emerald-500/20 uppercase">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
                      Pronto
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => handleDownloadInfo(b)}
                      className="text-gray-500 hover:text-emerald-400 p-2 rounded-lg hover:bg-emerald-500/10 transition-all active:scale-90"
                      title="Baixar informações do snapshot"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                      </svg>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Table, TableColumn } from '../types';

interface TableExplorerProps {
  tables: Table[];
  loading: boolean;
}

export const TableExplorer: React.FC<TableExplorerProps> = ({ tables, loading }) => {
  const [selectedTableId, setSelectedTableId] = useState<number | null>(null);

  const selectedTable = tables.find(t => t.id === selectedTableId);

  const handleExportSchema = () => {
    if (tables.length === 0) return;

    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(tables, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", `supabase-schema-backup-${new Date().toISOString().split('T')[0]}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();

    alert("✅ Estrutura baixada! Este arquivo contém o mapeamento de todas as suas tabelas e colunas.");
  };

  if (loading && tables.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-gray-500">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-emerald-500 mb-4"></div>
        <p className="text-sm font-medium">Carregando esquema do banco...</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-4 gap-6 animate-in slide-in-from-right-4 duration-500">
      <div className="md:col-span-1 space-y-4">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Tabelas ({tables.length})</h3>
          <button 
            onClick={handleExportSchema}
            className="text-[10px] bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500 hover:text-white px-2 py-1 rounded border border-emerald-500/20 font-bold transition-all active:scale-95"
          >
            EXPORTAR
          </button>
        </div>

        <div className="max-h-[60vh] overflow-y-auto space-y-1 pr-2 custom-scrollbar">
          {tables.length > 0 ? tables.map(table => (
            <button
              key={table.id}
              onClick={() => setSelectedTableId(table.id)}
              className={`w-full text-left px-4 py-3 rounded-xl text-sm transition-all flex items-center gap-3 border ${
                selectedTableId === table.id 
                  ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/40 shadow-inner' 
                  : 'text-gray-400 border-transparent hover:bg-gray-800/50 hover:text-white'
              }`}
            >
              <div className={`p-1.5 rounded-lg ${selectedTableId === table.id ? 'bg-emerald-500/20' : 'bg-gray-800'}`}>
                <svg className="w-3.5 h-3.5 opacity-70" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M3 14h18m-9-4v8m-7 0h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                </svg>
              </div>
              <span className="truncate font-medium">{table.name}</span>
            </button>
          )) : (
            <div className="p-4 text-center border border-dashed border-gray-800 rounded-xl">
              <p className="text-[10px] text-gray-600 uppercase">Vazio</p>
            </div>
          )}
        </div>
      </div>

      <div className="md:col-span-3">
        {selectedTable ? (
          <div className="glass-card rounded-2xl overflow-hidden border border-gray-800 shadow-xl">
            <div className="bg-gray-800/30 px-6 py-5 flex flex-col sm:flex-row sm:items-center justify-between border-b border-gray-800 gap-4">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <h3 className="text-xl font-bold text-white tracking-tight">{selectedTable.name}</h3>
                  <span className="text-[10px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/20">{selectedTable.schema}</span>
                </div>
                <p className="text-xs text-gray-500">Mapeamento de colunas e tipos de dados nativos do Postgres.</p>
              </div>
              <div className="flex gap-2">
                <span className="bg-gray-900 text-gray-400 px-3 py-1.5 rounded-lg text-[10px] font-bold border border-gray-800 shadow-sm">
                  {selectedTable.columns?.length || 0} COLUNAS
                </span>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead className="bg-gray-900/50 text-[10px] text-gray-500 uppercase font-black tracking-widest">
                  <tr>
