}

import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AppState, Project, Organization, Backup, Table } from './types';
import { supabaseApi } from './services/supabaseService';
import { Layout } from './components/Layout';
import { ProjectCard } from './components/ProjectCard';
import { BackupList } from './components/BackupList';
import { TokenInput } from './components/TokenInput';
import { TableExplorer } from './components/TableExplorer';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    try {
      return {
        token: localStorage.getItem('sb_token'),
        proxyUrl: localStorage.getItem('sb_proxy') || 'https://cors-anywhere.herokuapp.com/',
        organizations: [],
        projects: [],
        selectedProject: null,
        backups: [],
        tables: [],
        loading: false,
        error: null,
        activeView: 'dashboard',
      };
    } catch {
      return {
        token: null,
        proxyUrl: 'https://cors-anywhere.herokuapp.com/',
        organizations: [],
        projects: [],
        selectedProject: null,
        backups: [],
        tables: [],
        loading: false,
        error: null,
        activeView: 'dashboard',
      };
    }
  });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [analyzing, setAnalyzing] = useState(false);
  const [sqlQuery, setSqlQuery] = useState('SELECT * FROM information_schema.tables WHERE table_schema = \'public\';');
  const [sqlResults, setSqlResults] = useState<any[] | null>(null);

  const fetchData = useCallback(async (token: string, proxy: string) => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const [orgs, projs] = await Promise.all([
        supabaseApi.getOrganizations(token, proxy),
        supabaseApi.getProjects(token, proxy),
      ]);
      setState(prev => ({
        ...prev,
        organizations: orgs || [],
        projects: projs || [],
        loading: false,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Falha na conexão com a API',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token, state.proxyUrl);
    }
  }, [state.token, state.proxyUrl, fetchData]);

  const handleSetToken = (token: string, proxy: string) => {
    try {
      localStorage.setItem('sb_token', token);
      localStorage.setItem('sb_proxy', proxy);
    } catch (e) {}
    setState(prev => ({ ...prev, token, proxyUrl: proxy }));
  };

  const handleLogout = () => {
    try {
      localStorage.removeItem('sb_token');
      localStorage.removeItem('sb_proxy');
    } catch (e) {}
    setState({
      token: null,
      proxyUrl: 'https://cors-anywhere.herokuapp.com/',
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      tables: [],
      loading: false,
      error: null,
      activeView: 'dashboard',
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true, tables: [], backups: [] }));
    try {
      const [backups, tables] = await Promise.all([
        supabaseApi.getBackups(state.token, project.id, state.proxyUrl),
        supabaseApi.getTables(state.token, project.id, state.proxyUrl),
      ]);

      // Tenta pegar a contagem de linhas para cada tabela via SQL
      const updatedTables = [...tables];
      for (const table of updatedTables) {
         try {
           const countResult = await supabaseApi.executeSql(state.token, project.id, `SELECT count(*) FROM "${table.schema}"."${table.name}"`, state.proxyUrl);
           if (countResult && countResult[0]) {
             table.rowCount = parseInt(countResult[0].count);
           }
         } catch (e) {
           table.rowCount = 0;
         }
      }

      setState(prev => ({ ...prev, backups, tables: updatedTables, loading: false }));
      generateAiInsight(project, updatedTables);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const runCustomSql = async () => {
    if (!state.token || !state.selectedProject) return;
    setState(prev => ({ ...prev, loading: true }));
    try {
      const results = await supabaseApi.executeSql(state.token, state.selectedProject.id, sqlQuery, state.proxyUrl);
      setSqlResults(results);
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Erro ao executar SQL');
    } finally {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const generateAiInsight = async (project: Project, tables: Table[]) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const tableNames = tables.map(t => `${t.name} (${t.rowCount} linhas)`).join(', ');
      const prompt = `Como um analista de dados para o projeto ${project.name}, analise estas tabelas: ${tableNames || 'Nenhuma tabela detectada ainda'}. Sugira um insight ou verificação rápida de integridade para a região ${project.region}. Responda em Português em 2 frases curtas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Insight indisponível.');
    } catch (error) {
      setAiAnalysis('Gemini AI está fora de alcance.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-6 md:py-8">
        <header className="mb-6 flex flex-col gap-4">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold text-white mb-1 tracking-tight">Gerenciador</h1>
              <p className="text-xs text-gray-500 uppercase tracking-widest font-semibold">
                Status: <span className={state.error ? 'text-red-500' : 'text-emerald-500'}>{state.error ? 'Erro' : 'Conectado'}</span>
              </p>
            </div>

            <div className="flex bg-gray-900/80 p-1 rounded-xl border border-gray-800 w-full md:w-auto overflow-x-auto no-scrollbar">
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'dashboard'}))}
                className={`flex-shrink-0 px-6 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${state.activeView === 'dashboard' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Geral
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'explorer'}))}
                className={`flex-shrink-0 px-6 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${state.activeView === 'explorer' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Tabelas
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'sql'}))}
                className={`flex-shrink-0 px-6 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${state.activeView === 'sql' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                SQL Console
              </button>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          <aside className="lg:col-span-1 space-y-4">
            <h2 className="text-[10px] font-bold text-gray-600 uppercase tracking-[0.2em] px-2">Projetos</h2>
            <div className="space-y-2">
              {state.projects.map(p => (
                <ProjectCard 
                  key={p.id} 
                  project={p} 
                  isSelected={state.selectedProject?.id === p.id}
                  onClick={() => handleSelectProject(p)}
                />
              ))}
            </div>
          </aside>

          <section className="lg:col-span-3">
            {state.selectedProject ? (
              <div className="space-y-6">
                {state.activeView === 'dashboard' && (
                  <>
                    <div className="glass-card rounded-2xl p-6 md:p-8 border border-gray-800">
                      <div className="flex justify-between items-start mb-6">
                        <div>
                          <h2 className="text-2xl font-bold text-white mb-1">{state.selectedProject.name}</h2>
                          <p className="text-[10px] font-mono text-gray-500 uppercase">{state.selectedProject.id}</p>
                        </div>
                        <span className="text-[9px] bg-emerald-900/30 text-emerald-400 px-3 py-1 rounded-full border border-emerald-500/30 font-black">{state.selectedProject.status}</span>
                      </div>

                      <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-8">
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Região</p>
                          <p className="text-sm text-white">{state.selectedProject.region}</p>
                        </div>
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Tabelas Ativas</p>
                          <p className="text-sm text-white font-bold">{state.tables.length}</p>
                        </div>
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Total Linhas</p>
                          <p className="text-sm text-white font-bold">{state.tables.reduce((acc, t) => acc + (t.rowCount || 0), 0).toLocaleString()}</p>
                        </div>
                      </div>

                      <div className="bg-emerald-500/5 border border-emerald-500/10 p-4 rounded-xl">
                        <h3 className="text-[10px] font-bold text-emerald-500 uppercase mb-2">Insight AI</h3>
                        <p className="text-gray-300 text-sm italic">
                          {analyzing ? "Analisando métricas..." : aiAnalysis || "Selecione um projeto para análise."}
                        </p>
                      </div>
                    </div>
                    <BackupList backups={state.backups} onTriggerBackup={async () => {
                       await supabaseApi.triggerBackup(state.token!, state.selectedProject!.id, state.proxyUrl);
                       const b = await supabaseApi.getBackups(state.token!, state.selectedProject!.id, state.proxyUrl);
                       setState(s => ({...s, backups: b}));
                    }} />
                  </>
                )}

                {state.activeView === 'explorer' && (
                  <TableExplorer tables={state.tables} loading={state.loading} />
                )}

                {state.activeView === 'sql' && (
                  <div className="glass-card rounded-2xl p-6 border border-gray-800 space-y-4">
                    <h2 className="text-lg font-bold text-white">SQL Console</h2>
                    <textarea 
                      value={sqlQuery}
                      onChange={(e) => setSqlQuery(e.target.value)}
                      className="w-full h-32 bg-gray-900 text-emerald-400 font-mono text-xs p-4 rounded-xl border border-gray-800 outline-none focus:border-emerald-500/50"
                      placeholder="Execute comandos SQL aqui..."
                    />
                    <button 
                      onClick={runCustomSql}
                      className="bg-emerald-500 text-white font-bold text-xs px-6 py-3 rounded-xl hover:opacity-90 transition-all active:scale-95"
                    >
                      Executar Query
                    </button>

                    {sqlResults && (
                      <div className="mt-6 overflow-x-auto border border-gray-800 rounded-xl max-h-96 overflow-y-auto">
                        <table className="w-full text-left text-xs">
                          <thead className="bg-gray-800 text-gray-400 uppercase font-bold sticky top-0">
                            <tr>
                              {sqlResults.length > 0 && Object.keys(sqlResults[0]).map(k => (
                                <th key={k} className="px-4 py-3 border-b border-gray-700">{k}</th>
                              ))}
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-800 bg-gray-900/30">
                            {sqlResults.map((row, i) => (
                              <tr key={i} className="hover:bg-gray-800/50">
                                {Object.values(row).map((v: any, j) => (
                                  <td key={j} className="px-4 py-2 text-gray-300 truncate max-w-xs">{String(v)}</td>
                                ))}
                              </tr>
                            ))}
                          </tbody>
