                      </div>
                    )}
                  </div>
                )}
              </div>
            ) : (
              <div className="glass-card rounded-2xl p-16 text-center border-dashed border-2 border-gray-800 text-gray-600">
                Selecione um projeto para gerenciar dados e backups.
              </div>
            )}
          </section>
        </div>
      </div>
    </Layout>
  );
};

