const BASE_URL = 'https://api.supabase.com/v1';

const handleResponse = async (res: Response, context: string) => {
  if (res.ok) return res.json();

  if (res.status === 401) throw new Error(`Não Autorizado (401): Seu token sbp_... é inválido.`);
  if (res.status === 403) throw new Error(`Acesso Negado (403): O token não tem permissão para ${context}.`);
  if (res.status === 404) throw new Error(`O recurso ${context} não está disponível para o seu tipo de projeto (404).`);

  const errorData = await res.json().catch(() => ({}));
  throw new Error(`${context} falhou (${res.status}): ${errorData.message || res.statusText}`);
};

export const supabaseApi = {
  getOrganizations: async (token: string, proxy: string = ''): Promise<Organization[]> => {
    try {
      const url = `${proxy}${BASE_URL}/organizations`;
      const res = await fetch(url, {
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Accept': 'application/json'
        },
      });
      return handleResponse(res, 'Organizações');
    } catch (err) {
      console.error('Fetch error:', err);
      throw new Error('Erro de Conexão: O navegador ou o Proxy bloqueou a requisição.');
    }
  },

  getProjects: async (token: string, proxy: string = ''): Promise<Project[]> => {
    const url = `${proxy}${BASE_URL}/projects`;
    const res = await fetch(url, {
      headers: { 'Authorization': `Bearer ${token}` },
    });
    return handleResponse(res, 'Projetos');
  },

  getBackups: async (token: string, projectRef: string, proxy: string = ''): Promise<Backup[]> => {
    try {
      const url = `${proxy}${BASE_URL}/projects/${projectRef}/backups`;
      const res = await fetch(url, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      if (!res.ok) return [];
      return res.json();
    } catch {
      return [];
    }
  },

  executeSql: async (token: string, projectRef: string, query: string, proxy: string = ''): Promise<any[]> => {
    const url = `${proxy}${BASE_URL}/projects/${projectRef}/database/query`;
    const res = await fetch(url, {
      method: 'POST',
      headers: { 
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ query })
    });
    return handleResponse(res, 'Query SQL');
  },

  getTables: async (token: string, projectRef: string, proxy: string = ''): Promise<Table[]> => {
    try {
      const url = `${proxy}${BASE_URL}/projects/${projectRef}/database/tables`;
      const res = await fetch(url, {
        headers: { 'Authorization': `Bearer ${token}` },
      });

      let tables: Table[] = [];
      if (res.ok) {
        tables = await res.json();
      }

      if (!tables || tables.length === 0) {
        const fallbackQuery = `
          SELECT 
            t.table_name as name, 
            t.table_schema as schema
          FROM information_schema.tables t
          WHERE t.table_schema = 'public' AND t.table_type = 'BASE TABLE';
        `;
        const sqlResults = await supabaseApi.executeSql(token, projectRef, fallbackQuery, proxy);
        tables = sqlResults.map((r, idx) => ({ id: idx, name: r.name, schema: r.schema }));
      }
      return tables;
    } catch (e) {
      return [];
    }
  }
};

import React, { useState } from 'react';
import { Backup, Table } from '../types';
import { supabaseApi } from '../services/supabaseService';

interface BackupListProps {
  backups: Backup[];
  tables: Table[];
  projectRef: string;
  token: string;
  proxy: string;
}

export const BackupList: React.FC<BackupListProps> = ({ backups, tables, projectRef, token, proxy }) => {
  const [exporting, setExporting] = useState(false);
  const [progress, setProgress] = useState(0);

  const handleLogicalBackup = async () => {
    if (tables.length === 0) {
      alert("Nenhuma tabela encontrada para backup.");
      return;
    }

    setExporting(true);
    setProgress(0);
    const backupData: Record<string, any[]> = {};

    try {
      for (let i = 0; i < tables.length; i++) {
        const table = tables[i];
        // Busca os dados de cada tabela via SQL (limitando para evitar crash no tablet)
        const query = `SELECT * FROM "${table.schema}"."${table.name}" LIMIT 5000`;
        const rows = await supabaseApi.executeSql(token, projectRef, query, proxy);
        backupData[table.name] = rows;
        setProgress(Math.round(((i + 1) / tables.length) * 100));
      }

      // Gera o arquivo para download
      const fullBackup = {
        project_ref: projectRef,
        timestamp: new Date().toISOString(),
        data: backupData
      };

      const blob = new Blob([JSON.stringify(fullBackup, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `supabase-data-backup-${new Date().toISOString().split('T')[0]}.json`;
      a.click();
      URL.revokeObjectURL(url);

      alert("✅ Backup de dados concluído e baixado com sucesso!");
    } catch (err) {
      alert("Erro ao gerar backup de dados: " + (err instanceof Error ? err.message : 'Erro desconhecido'));
    } finally {
      setExporting(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Seção de Backup de Dados Real (Manual) */}
      <div className="glass-card rounded-2xl p-6 border border-emerald-500/30 bg-emerald-500/5 shadow-lg shadow-emerald-500/5">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-emerald-500/20 rounded-xl flex items-center justify-center text-emerald-500">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
              </svg>
            </div>
            <div>
              <h3 className="text-lg font-bold text-white">Backup Manual de Dados</h3>
              <p className="text-xs text-gray-500">Extrai todos os registros das suas tabelas e baixa como um arquivo JSON.</p>
            </div>
          </div>
          <button 
            onClick={handleLogicalBackup}
            disabled={exporting}
            className={`px-8 py-3 rounded-xl font-bold text-sm transition-all flex items-center gap-3 shadow-xl ${
              exporting 
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                : 'bg-emerald-500 text-white hover:brightness-110 active:scale-95'
            }`}
          >
            {exporting ? (
              <>
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                Processando {progress}%
              </>
            ) : (
              'Baixar Backup de Dados'
            )}
          </button>
        </div>
      </div>

      {/* Seção de Snapshots (Informativo) */}
      <div className="glass-card rounded-xl overflow-hidden border border-gray-800">
        <div className="px-6 py-5 border-b border-gray-800 bg-gray-900/20">
          <h3 className="font-bold text-white">Snapshots de Infraestrutura (PITR)</h3>
          <p className="text-xs text-gray-500 mt-1">Pontos de restauração gerenciados automaticamente pelo Supabase.</p>
        </div>

        {backups.length === 0 ? (
          <div className="p-10 text-center text-gray-600 text-sm italic">
            Nenhum snapshot de infraestrutura disponível no momento.
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-gray-800/40 text-[10px] text-gray-400 uppercase font-bold tracking-widest">
                <tr>
                  <th className="px-6 py-4">Data</th>
                  <th className="px-6 py-4">Tipo</th>
                  <th className="px-6 py-4">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-800/50">
                {backups.map((b) => (
                  <tr key={b.id} className="text-sm hover:bg-gray-800/30">
                    <td className="px-6 py-4 text-white">{new Date(b.inserted_at).toLocaleString()}</td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] bg-blue-900/20 text-blue-400 px-2 py-0.5 rounded border border-blue-500/20">
                        {b.is_physical ? 'PITR' : 'LOGICAL'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] text-emerald-500 font-bold uppercase tracking-tighter">PRONTO</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AppState, Project, Organization, Backup, Table } from './types';
import { supabaseApi } from './services/supabaseService';
import { Layout } from './components/Layout';
import { ProjectCard } from './components/ProjectCard';
import { BackupList } from './components/BackupList';
import { TokenInput } from './components/TokenInput';
import { TableExplorer } from './components/TableExplorer';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    try {
      return {
        token: localStorage.getItem('sb_token'),
        proxyUrl: localStorage.getItem('sb_proxy') || 'https://cors-anywhere.herokuapp.com/',
        organizations: [],
        projects: [],
        selectedProject: null,
        backups: [],
        tables: [],
        loading: false,
        error: null,
        activeView: 'dashboard',
      };
    } catch {
      return {
        token: null,
        proxyUrl: 'https://cors-anywhere.herokuapp.com/',
        organizations: [],
        projects: [],
        selectedProject: null,
        backups: [],
        tables: [],
        loading: false,
        error: null,
        activeView: 'dashboard',
      };
    }
  });

  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [analyzing, setAnalyzing] = useState(false);
  const [sqlQuery, setSqlQuery] = useState('SELECT * FROM information_schema.tables WHERE table_schema = \'public\';');
  const [sqlResults, setSqlResults] = useState<any[] | null>(null);

  const fetchData = useCallback(async (token: string, proxy: string) => {
    setState(prev => ({ ...prev, loading: true, error: null }));
    try {
      const [orgs, projs] = await Promise.all([
        supabaseApi.getOrganizations(token, proxy),
        supabaseApi.getProjects(token, proxy),
      ]);
      setState(prev => ({
        ...prev,
        organizations: orgs || [],
        projects: projs || [],
        loading: false,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Falha na conexão com a API',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token, state.proxyUrl);
    }
  }, [state.token, state.proxyUrl, fetchData]);

  const handleSetToken = (token: string, proxy: string) => {
    try {
      localStorage.setItem('sb_token', token);
      localStorage.setItem('sb_proxy', proxy);
    } catch (e) {}
    setState(prev => ({ ...prev, token, proxyUrl: proxy }));
  };

  const handleLogout = () => {
    try {
      localStorage.removeItem('sb_token');
      localStorage.removeItem('sb_proxy');
    } catch (e) {}
    setState({
      token: null,
      proxyUrl: 'https://cors-anywhere.herokuapp.com/',
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      tables: [],
      loading: false,
      error: null,
      activeView: 'dashboard',
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true, tables: [], backups: [] }));
    try {
      const [backups, tables] = await Promise.all([
        supabaseApi.getBackups(state.token, project.id, state.proxyUrl),
        supabaseApi.getTables(state.token, project.id, state.proxyUrl),
      ]);

      const updatedTables = [...tables];
      for (const table of updatedTables) {
         try {
           const countResult = await supabaseApi.executeSql(state.token, project.id, `SELECT count(*) FROM "${table.schema}"."${table.name}"`, state.proxyUrl);
           if (countResult && countResult[0]) {
             table.rowCount = parseInt(countResult[0].count);
           }
         } catch (e) {
           table.rowCount = 0;
         }
      }

      setState(prev => ({ ...prev, backups, tables: updatedTables, loading: false }));
      generateAiInsight(project, updatedTables);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const runCustomSql = async () => {
    if (!state.token || !state.selectedProject) return;
    setState(prev => ({ ...prev, loading: true }));
    try {
      const results = await supabaseApi.executeSql(state.token, state.selectedProject.id, sqlQuery, state.proxyUrl);
      setSqlResults(results);
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Erro ao executar SQL');
    } finally {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const generateAiInsight = async (project: Project, tables: Table[]) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const tableNames = tables.map(t => `${t.name} (${t.rowCount} linhas)`).join(', ');
      const prompt = `Como um analista de dados para o projeto ${project.name}, analise estas tabelas: ${tableNames || 'Nenhuma tabela detectada ainda'}. Sugira um insight ou verificação rápida de integridade para a região ${project.region}. Responda em Português em 2 frases curtas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Insight indisponível.');
    } catch (error) {
      setAiAnalysis('Gemini AI está fora de alcance.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-6 md:py-8">
        <header className="mb-6 flex flex-col gap-4">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold text-white mb-1 tracking-tight">Gerenciador</h1>
              <p className="text-xs text-gray-500 uppercase tracking-widest font-semibold">
                Status: <span className={state.error ? 'text-red-500' : 'text-emerald-500'}>{state.error ? 'Erro' : 'Conectado'}</span>
              </p>
            </div>

            <div className="flex bg-gray-900/80 p-1 rounded-xl border border-gray-800 w-full md:w-auto overflow-x-auto no-scrollbar">
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'dashboard'}))}
                className={`flex-shrink-0 px-6 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${state.activeView === 'dashboard' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Geral
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'explorer'}))}
                className={`flex-shrink-0 px-6 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${state.activeView === 'explorer' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Tabelas
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'sql'}))}
                className={`flex-shrink-0 px-6 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${state.activeView === 'sql' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                SQL Console
              </button>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          <aside className="lg:col-span-1 space-y-4">
            <h2 className="text-[10px] font-bold text-gray-600 uppercase tracking-[0.2em] px-2">Projetos</h2>
            <div className="space-y-2">
              {state.projects.map(p => (
                <ProjectCard 
                  key={p.id} 
                  project={p} 
                  isSelected={state.selectedProject?.id === p.id}
                  onClick={() => handleSelectProject(p)}
                />
              ))}
            </div>
          </aside>

          <section className="lg:col-span-3">
            {state.selectedProject ? (
              <div className="space-y-6">
                {state.activeView === 'dashboard' && (
                  <>
                    <div className="glass-card rounded-2xl p-6 md:p-8 border border-gray-800">
                      <div className="flex justify-between items-start mb-6">
                        <div>
                          <h2 className="text-2xl font-bold text-white mb-1">{state.selectedProject.name}</h2>
                          <p className="text-[10px] font-mono text-gray-500 uppercase">{state.selectedProject.id}</p>
                        </div>
                        <span className="text-[9px] bg-emerald-900/30 text-emerald-400 px-3 py-1 rounded-full border border-emerald-500/30 font-black">{state.selectedProject.status}</span>
                      </div>

                      <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-8">
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Região</p>
                          <p className="text-sm text-white">{state.selectedProject.region}</p>
                        </div>
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Tabelas Ativas</p>
                          <p className="text-sm text-white font-bold">{state.tables.length}</p>
                        </div>
                        <div className="bg-gray-900/50 p-4 rounded-xl border border-gray-800">
                          <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Total Linhas</p>
                          <p className="text-sm text-white font-bold">{state.tables.reduce((acc, t) => acc + (t.rowCount || 0), 0).toLocaleString()}</p>
                        </div>
                      </div>

                      <div className="bg-emerald-500/5 border border-emerald-500/10 p-4 rounded-xl">
                        <h3 className="text-[10px] font-bold text-emerald-500 uppercase mb-2">Insight AI</h3>
                        <p className="text-gray-300 text-sm italic">
                          {analyzing ? "Analisando métricas..." : aiAnalysis || "Selecione um projeto para análise."}
                        </p>
                      </div>
                    </div>

                    <BackupList 
                      backups={state.backups} 
                      tables={state.tables}
                      projectRef={state.selectedProject.id}
                      token={state.token!}
                      proxy={state.proxyUrl}
                    />
                  </>
                )}

                {state.activeView === 'explorer' && (
                  <TableExplorer tables={state.tables} loading={state.loading} />
                )}

                {state.activeView === 'sql' && (
                  <div className="glass-card rounded-2xl p-6 border border-gray-800 space-y-4">
                    <h2 className="text-lg font-bold text-white">SQL Console</h2>
                    <textarea 
                      value={sqlQuery}
                      onChange={(e) => setSqlQuery(e.target.value)}
                      className="w-full h-32 bg-gray-900 text-emerald-400 font-mono text-xs p-4 rounded-xl border border-gray-800 outline-none focus:border-emerald-500/50"
                      placeholder="Execute comandos SQL aqui..."
                    />
                    <button 
                      onClick={runCustomSql}
                      className="bg-emerald-500 text-white font-bold text-xs px-6 py-3 rounded-xl hover:opacity-90 transition-all active:scale-95"
                    >
                      Executar Query
                    </button>

                    {sqlResults && (
                      <div className="mt-6 overflow-x-auto border border-gray-800 rounded-xl max-h-96 overflow-y-auto">
                        <table className="w-full text-left text-xs">
                          <thead className="bg-gray-800 text-gray-400 uppercase font-bold sticky top-0">
                            <tr>
                              {sqlResults.length > 0 && Object.keys(sqlResults[0]).map(k => (
                                <th key={k} className="px-4 py-3 border-b border-gray-700">{k}</th>
                              ))}
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-800 bg-gray-900/30">
                            {sqlResults.map((row, i) => (
                              <tr key={i} className="hover:bg-gray-800/50">
                                {Object.values(row).map((v: any, j) => (
                                  <td key={j} className="px-4 py-2 text-gray-300 truncate max-w-xs">{String(v)}</td>
                                ))}
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    )}
                  </div>
                )}
              </div>
            ) : (
              <div className="glass-card rounded-2xl p-16 text-center border-dashed border-2 border-gray-800 text-gray-600">
                Selecione um projeto para gerenciar dados e backups.
              </div>
            )}
          </section>
        </div>
      </div>
    </Layout>
  );
};

