        ...prev,
        organizations: orgs || [],
        projects: projs || [],
        loading: false,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        error: err instanceof Error ? err.message : 'Falha na conexão com a API',
        loading: false,
      }));
    }
  }, []);

  useEffect(() => {
    if (state.token) {
      fetchData(state.token, state.proxyUrl);
    }
  }, [state.token, state.proxyUrl, fetchData]);

  const handleSetToken = (token: string, proxy: string) => {
    try {
      localStorage.setItem('sb_token', token);
      localStorage.setItem('sb_proxy', proxy);
    } catch (e) {}
    setState(prev => ({ ...prev, token, proxyUrl: proxy }));
  };

  const handleLogout = () => {
    try {
      localStorage.removeItem('sb_token');
      localStorage.removeItem('sb_proxy');
    } catch (e) {}
    setState({
      token: null,
      proxyUrl: 'https://cors-anywhere.herokuapp.com/',
      organizations: [],
      projects: [],
      selectedProject: null,
      backups: [],
      tables: [],
      loading: false,
      error: null,
      activeView: 'dashboard',
    });
  };

  const handleSelectProject = async (project: Project) => {
    if (!state.token) return;
    setState(prev => ({ ...prev, selectedProject: project, loading: true, tables: [], backups: [] }));
    try {
      const [backups, tables] = await Promise.all([
        supabaseApi.getBackups(state.token, project.id, state.proxyUrl),
        supabaseApi.getTables(state.token, project.id, state.proxyUrl),
      ]);

      const updatedTables = [...tables];
      for (const table of updatedTables) {
         try {
           const countResult = await supabaseApi.executeSql(state.token, project.id, `SELECT count(*) FROM "${table.schema}"."${table.name}"`, state.proxyUrl);
           if (countResult && countResult[0]) {
             table.rowCount = parseInt(countResult[0].count);
           }
         } catch (e) {
           table.rowCount = 0;
         }
      }

      setState(prev => ({ ...prev, backups, tables: updatedTables, loading: false }));
      generateAiInsight(project, updatedTables);
    } catch (err) {
      setState(prev => ({ ...prev, loading: false, error: err instanceof Error ? err.message : 'Erro ao carregar projeto' }));
    }
  };

  const runCustomSql = async () => {
    if (!state.token || !state.selectedProject) return;
    setState(prev => ({ ...prev, loading: true }));
    try {
      const results = await supabaseApi.executeSql(state.token, state.selectedProject.id, sqlQuery, state.proxyUrl);
      setSqlResults(results);
    } catch (err) {
      alert(err instanceof Error ? err.message : 'Erro ao executar SQL');
    } finally {
      setState(prev => ({ ...prev, loading: false }));
    }
  };

  const generateAiInsight = async (project: Project, tables: Table[]) => {
    setAnalyzing(true);
    setAiAnalysis('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const tableNames = tables.map(t => `${t.name} (${t.rowCount} linhas)`).join(', ');
      const prompt = `Como um analista de dados para o projeto ${project.name}, analise estas tabelas: ${tableNames || 'Nenhuma tabela detectada ainda'}. Sugira um insight ou verificação rápida de integridade para a região ${project.region}. Responda em Português em 2 frases curtas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Insight indisponível.');
    } catch (error) {
      setAiAnalysis('Gemini AI está fora de alcance.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-6 md:py-8">
        <header className="mb-6 flex flex-col gap-4">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold text-white mb-1 tracking-tight">Painel de Controle</h1>
              <p className="text-xs text-gray-500 uppercase tracking-widest font-semibold">
                Sincronização: <span className={state.error ? 'text-red-500' : 'text-emerald-500'}>{state.error ? 'Falha' : 'Ativa'}</span>
              </p>
            </div>

            <div className="flex bg-gray-900/80 p-1.5 rounded-2xl border border-gray-800 w-full md:w-auto overflow-x-auto no-scrollbar shadow-2xl">
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'dashboard'}))}
                className={`flex-shrink-0 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${state.activeView === 'dashboard' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Geral
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'backup'}))}
                className={`flex-shrink-0 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${state.activeView === 'backup' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Backup
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'explorer'}))}
                className={`flex-shrink-0 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${state.activeView === 'explorer' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                Tabelas
              </button>
              <button
                onClick={() => setState(prev => ({...prev, activeView: 'sql'}))}
                className={`flex-shrink-0 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${state.activeView === 'sql' ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
              >
                SQL Console
              </button>
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          <aside className="lg:col-span-1 space-y-4">
            <h2 className="text-[10px] font-bold text-gray-600 uppercase tracking-[0.2em] px-2 flex items-center justify-between">
              Projetos 
              <span className="bg-gray-800 text-gray-500 px-1.5 py-0.5 rounded-md text-[8px]">{state.projects.length}</span>
            </h2>
            <div className="space-y-2">
              {state.projects.map(p => (
                <ProjectCard 
                  key={p.id} 
                  project={p} 
                  isSelected={state.selectedProject?.id === p.id}
                  onClick={() => handleSelectProject(p)}
                />
              ))}
            </div>
          </aside>

          <section className="lg:col-span-3">
            {state.selectedProject ? (
              <div className="space-y-6">
                {state.activeView === 'dashboard' && (
                  <>
                    <div className="glass-card rounded-3xl p-6 md:p-8 border border-gray-800 shadow-2xl relative overflow-hidden">
                      <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none">
                         <div className="w-32 h-32 supabase-gradient rounded-full blur-3xl"></div>
                      </div>

                      <div className="flex justify-between items-start mb-8">
                        <div>
                          <h2 className="text-3xl font-black text-white mb-2 tracking-tight">{state.selectedProject.name}</h2>
                          <div className="flex items-center gap-2">
                            <span className="text-[10px] font-mono text-gray-500 bg-gray-800 px-2 py-0.5 rounded">{state.selectedProject.id}</span>
                            <span className="text-[10px] font-mono text-emerald-500 bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">{state.selectedProject.region}</span>
                          </div>
                        </div>
                        <div className="flex flex-col items-end gap-2">
                          <span className="text-[10px] bg-emerald-950/30 text-emerald-400 px-4 py-1.5 rounded-full border border-emerald-500/30 font-black tracking-widest uppercase">
                            {state.selectedProject.status}
                          </span>
                        </div>
                      </div>

                      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
                        <div className="bg-gray-900/60 p-5 rounded-2xl border border-gray-800/50 hover:border-emerald-500/30 transition-all">
                          <p className="text-[10px] text-gray-500 font-black uppercase mb-2 tracking-wider">Tabelas</p>
                          <p className="text-2xl text-white font-black">{state.tables.length}</p>
                        </div>
                        <div className="bg-gray-900/60 p-5 rounded-2xl border border-gray-800/50 hover:border-emerald-500/30 transition-all">
                          <p className="text-[10px] text-gray-500 font-black uppercase mb-2 tracking-wider">Total de Registros</p>
                          <p className="text-2xl text-white font-black">{state.tables.reduce((acc, t) => acc + (t.rowCount || 0), 0).toLocaleString()}</p>
                        </div>
                        <div className="bg-gray-900/60 p-5 rounded-2xl border border-gray-800/50 hover:border-emerald-500/30 transition-all">
                          <p className="text-[10px] text-gray-500 font-black uppercase mb-2 tracking-wider">Última Verificação</p>
                          <p className="text-2xl text-white font-black">{new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                        </div>
                      </div>

                      <div className="bg-emerald-500/5 border border-emerald-500/10 p-5 rounded-2xl flex items-start gap-4">
                        <div className="mt-1 text-emerald-500">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                          </svg>
                        </div>
                        <div>
                          <h3 className="text-[10px] font-black text-emerald-500 uppercase mb-1 tracking-widest">Insight AI Instantâneo</h3>
                          <p className="text-gray-300 text-sm leading-relaxed">
                            {analyzing ? "Processando metadados do projeto..." : aiAnalysis || "Selecione um projeto para gerar análise."}
                          </p>
                        </div>
                      </div>
                    </div>
                  </>
                )}

                {state.activeView === 'backup' && (
                  <BackupList 
                    backups={state.backups} 
                    tables={state.tables}
                    projectRef={state.selectedProject.id}
                    token={state.token!}
                    proxy={state.proxyUrl}
                  />
                )}

                {state.activeView === 'explorer' && (
                  <TableExplorer tables={state.tables} loading={state.loading} />
                )}

                {state.activeView === 'sql' && (
                  <div className="glass-card rounded-3xl p-6 md:p-8 border border-gray-800 space-y-6 shadow-2xl">
                    <div className="flex items-center justify-between">
                       <h2 className="text-xl font-black text-white uppercase tracking-tight">Console SQL Especializado</h2>
                       <span className="text-[10px] text-gray-500 font-mono">Modo: Direto via Management API</span>
                    </div>
                    <textarea 
                      value={sqlQuery}
                      onChange={(e) => setSqlQuery(e.target.value)}
                      className="w-full h-48 bg-gray-900/80 text-emerald-400 font-mono text-sm p-6 rounded-2xl border border-gray-800 outline-none focus:border-emerald-500/50 shadow-inner"
                      placeholder="Ex: SELECT * FROM public.minha_tabela LIMIT 10;"
                    />
                    <div className="flex items-center justify-between gap-4">
                      <p className="text-[10px] text-gray-500 max-w-md">Utilize o console para rodar diagnósticos rápidos ou exportar subconjuntos de dados específicos.</p>
                      <button 
                        onClick={runCustomSql}
                        className="bg-emerald-500 text-white font-black text-xs px-8 py-4 rounded-2xl hover:brightness-110 transition-all active:scale-95 shadow-xl shadow-emerald-500/10 flex items-center gap-2"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                        EXECUTAR AGORA
                      </button>
                    </div>

                    {sqlResults && (
                      <div className="mt-8 overflow-hidden border border-gray-800 rounded-2xl shadow-2xl bg-gray-950/50">
                        <div className="overflow-x-auto max-h-[500px] overflow-y-auto custom-scrollbar">
                          <table className="w-full text-left text-xs border-collapse">
                            <thead className="bg-gray-900 text-gray-400 uppercase font-black sticky top-0 z-10 border-b border-gray-800">
                              <tr>
                                {sqlResults.length > 0 && Object.keys(sqlResults[0]).map(k => (
                                  <th key={k} className="px-6 py-4 whitespace-nowrap">{k}</th>
                                ))}
                              </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-800/50">
                              {sqlResults.map((row, i) => (
                                <tr key={i} className="hover:bg-emerald-500/5 transition-colors">
                                  {Object.values(row).map((v: any, j) => (
                                    <td key={j} className="px-6 py-3 text-gray-300 font-mono whitespace-nowrap max-w-xs truncate">{String(v)}</td>
                                  ))}
                                </tr>
                              ))}
                              {sqlResults.length === 0 && (
                                <tr>
                                  <td className="px-6 py-10 text-center text-gray-500 italic" colSpan={100}>Nenhum registro retornado.</td>
                                </tr>
                              )}
                            </tbody>
                          </table>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            ) : (
              <div className="glass-card rounded-3xl p-20 text-center border-dashed border-2 border-gray-800/50 flex flex-col items-center justify-center gap-4">
                <div className="w-16 h-16 bg-gray-900 rounded-3xl flex items-center justify-center text-gray-700">
                   <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                   </svg>
                </div>
                <div>
                  <h3 className="text-xl font-bold text-gray-400 mb-1">Selecione um Projeto</h3>
                  <p className="text-sm text-gray-600">Escolha um projeto na barra lateral para acessar ferramentas de backup e exploração.</p>
                </div>
              </div>
            )}
          </section>
        </div>
      </div>
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Backup, Table } from '../types';
import { supabaseApi } from '../services/supabaseService';

interface BackupListProps {
  backups: Backup[];
  tables: Table[];
  projectRef: string;
  token: string;
  proxy: string;
}

export const BackupList: React.FC<BackupListProps> = ({ backups, tables, projectRef, token, proxy }) => {
  const [exporting, setExporting] = useState(false);
  const [progress, setProgress] = useState(0);
  const [currentTable, setCurrentTable] = useState('');

  const handleLogicalBackup = async () => {
    if (tables.length === 0) {
      alert("⚠️ Nenhuma tabela encontrada no esquema público.");
      return;
    }

    const confirmBackup = window.confirm(`Deseja iniciar o backup de ${tables.length} tabelas? Os dados serão baixados em um arquivo JSON.`);
    if (!confirmBackup) return;

    setExporting(true);
    setProgress(0);
    const backupData: Record<string, any[]> = {};

    try {
      for (let i = 0; i < tables.length; i++) {
        const table = tables[i];
        setCurrentTable(table.name);

        // Busca os dados (Limitado a 10k por tabela para evitar quebra de memória no navegador)
        const query = `SELECT * FROM "${table.schema}"."${table.name}" LIMIT 10000`;
        try {
          const rows = await supabaseApi.executeSql(token, projectRef, query, proxy);
          backupData[table.name] = rows;
        } catch (e) {
          console.error(`Falha ao exportar tabela ${table.name}:`, e);
          backupData[table.name] = []; // Mantém a chave mas vazia se falhar (ex: RLS bloqueando)
        }

        setProgress(Math.round(((i + 1) / tables.length) * 100));
      }

      const fullBackup = {
        project: projectRef,
        generated_at: new Date().toISOString(),
        tables_count: tables.length,
        content: backupData
      };

      const blob = new Blob([JSON.stringify(fullBackup, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `backup_${projectRef}_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

      alert("✅ Backup concluído com sucesso! O download do arquivo JSON iniciou.");
    } catch (err) {
      alert("❌ Erro fatal durante o backup: " + (err instanceof Error ? err.message : 'Erro desconhecido'));
    } finally {
      setExporting(false);
      setCurrentTable('');
    }
  };

  const handleStructureBackup = async () => {
    setExporting(true);
    setCurrentTable('Extraindo Estrutura (DDL)...');
    try {
      const ddlQuery = `
        SELECT 
          'CREATE TABLE ' || table_name || ' (' || 
          string_agg(column_name || ' ' || data_type || CASE WHEN is_nullable = 'NO' THEN ' NOT NULL' ELSE '' END, ', ') || 
          ');' as ddl
        FROM information_schema.columns
        WHERE table_schema = 'public'
        GROUP BY table_name;
      `;
      const results = await supabaseApi.executeSql(token, projectRef, ddlQuery, proxy);
      const sqlContent = results.map(r => r.ddl).join('\n\n');

      const blob = new Blob([sqlContent], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `schema_${projectRef}.sql`;
      link.click();
      URL.revokeObjectURL(url);
      alert("✅ Estrutura do banco exportada como arquivo .SQL");
    } catch (e) {
      alert("Erro ao exportar estrutura: " + (e instanceof Error ? e.message : 'Erro'));
    } finally {
      setExporting(false);
      setCurrentTable('');
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Card de Backup de Dados */}
        <div className="glass-card rounded-3xl p-8 border border-emerald-500/30 bg-emerald-500/5 relative overflow-hidden group">
          <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500"></div>
          <div className="flex flex-col h-full justify-between">
            <div>
              <div className="w-14 h-14 bg-emerald-500/10 rounded-2xl flex items-center justify-center text-emerald-500 mb-6 group-hover:scale-110 transition-transform">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h3 className="text-xl font-black text-white mb-2 uppercase tracking-tight">Exportar Dados (JSON)</h3>
              <p className="text-sm text-gray-400 leading-relaxed mb-6">Recomendado para migrações rápidas ou salvaguarda local. Baixa todos os registros das tabelas detectadas no esquema público.</p>
            </div>

            <button 
              onClick={handleLogicalBackup}
              disabled={exporting}
              className={`w-full py-4 rounded-2xl font-black text-xs tracking-widest uppercase transition-all shadow-2xl ${
                exporting 
                  ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                  : 'bg-emerald-500 text-white hover:brightness-110 active:scale-[0.98]'
              }`}
            >
              {exporting ? 'Exportando Registros...' : 'Baixar Dados Completos'}
            </button>
          </div>
        </div>

        {/* Card de Backup de Estrutura */}
        <div className="glass-card rounded-3xl p-8 border border-blue-500/30 bg-blue-500/5 relative overflow-hidden group">
          <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
          <div className="flex flex-col h-full justify-between">
            <div>
              <div className="w-14 h-14 bg-blue-500/10 rounded-2xl flex items-center justify-center text-blue-500 mb-6 group-hover:scale-110 transition-transform">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                </svg>
              </div>
              <h3 className="text-xl font-black text-white mb-2 uppercase tracking-tight">Exportar Schema (SQL)</h3>
              <p className="text-sm text-gray-400 leading-relaxed mb-6">Gera um arquivo .sql com a estrutura das suas tabelas. Ideal para documentação técnica ou restauração de arquitetura em novos bancos.</p>
            </div>

            <button 
              onClick={handleStructureBackup}
              disabled={exporting}
              className={`w-full py-4 rounded-2xl font-black text-xs tracking-widest uppercase transition-all shadow-2xl ${
                exporting 
                  ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                  : 'bg-blue-500 text-white hover:brightness-110 active:scale-[0.98]'
              }`}
            >
              {exporting ? 'Extraindo SQL...' : 'Baixar Script de Estrutura'}
            </button>
          </div>
        </div>
      </div>

      {/* Indicador de Progresso Global */}
      {exporting && (
        <div className="glass-card rounded-3xl p-8 border border-gray-800 bg-gray-900/40 shadow-2xl">
          <div className="flex items-center justify-between mb-4">
            <div>
              <p className="text-xs font-black text-emerald-500 uppercase tracking-widest">Processando Backup Lógico</p>
              <h4 className="text-lg font-bold text-white mt-1">Extraindo: <span className="font-mono text-gray-400">{currentTable}</span></h4>
            </div>
            <span className="text-2xl font-black text-white">{progress}%</span>
          </div>
          <div className="w-full h-3 bg-gray-800 rounded-full overflow-hidden shadow-inner">
            <div 
              className="h-full bg-emerald-500 transition-all duration-500 ease-out shadow-[0_0_15px_rgba(16,185,129,0.5)]"
              style={{ width: `${progress}%` }}
            ></div>
          </div>
          <p className="text-[10px] text-gray-600 mt-4 uppercase tracking-tighter">Nota: Não feche esta aba enquanto o progresso não atingir 100%. Para bancos muito grandes (>100k linhas), o navegador pode exigir confirmação de download múltiplo.</p>
        </div>
      )}

      {/* Snapshots do Supabase (Apenas Leitura) */}
      <div className="glass-card rounded-2xl overflow-hidden border border-gray-800">
        <div className="px-6 py-5 bg-gray-800/20 flex items-center gap-3 border-b border-gray-800">
          <div className="w-2 h-2 rounded-full bg-blue-500"></div>
          <h3 className="font-black text-white text-[10px] uppercase tracking-widest">Snapshots de Sistema (PITR)</h3>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs">
            <thead className="bg-gray-900/50 text-gray-500 font-bold uppercase tracking-tighter">
              <tr>
                <th className="px-6 py-4">Data de Inserção</th>
