            </thead>
            <tbody className="divide-y divide-gray-800/50">
              {backups.length > 0 ? backups.map((b) => (
                <tr key={b.id} className="text-gray-400 hover:bg-gray-800/30">
                  <td className="px-6 py-4 font-mono">{new Date(b.inserted_at).toLocaleString()}</td>
