  const runQuickBackup = async () => {
    if (!state.token || !state.selectedProject || state.tables.length === 0) return;

    setBackupProgress({active: true, percent: 0});
    const backupData: Record<string, any[]> = {};

    try {
      for (let i = 0; i < state.tables.length; i++) {
        const table = state.tables[i];
        const query = `SELECT * FROM "${table.schema}"."${table.name}" LIMIT 5000`;
        const rows = await supabaseApi.executeSql(state.token, state.selectedProject.id, query, state.proxyUrl);
        backupData[table.name] = rows;
        setBackupProgress({active: true, percent: Math.round(((i + 1) / state.tables.length) * 100)});
      }

      const blob = new Blob([JSON.stringify({project: state.selectedProject.name, date: new Date().toISOString(), data: backupData}, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `backup_${state.selectedProject.name}_${new Date().toISOString().split('T')[0]}.json`;
