    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const tableNames = tables.map(t => `${t.name} (${t.rowCount} linhas)`).join(', ');
      const prompt = `Analise o projeto Supabase ${project.name} com as tabelas: ${tableNames}. Dê um conselho de segurança ou backup em Português (máximo 15 palavras).`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiAnalysis(response.text || 'Insight indisponível.');
    } catch (error) {
      setAiAnalysis('Gemini AI está fora de alcance.');
    } finally {
      setAnalyzing(false);
    }
  };

  if (!state.token) {
    return <TokenInput onSetToken={handleSetToken} />;
  }

  return (
    <Layout 
      onLogout={handleLogout} 
      loading={state.loading} 
      organizations={state.organizations}
    >
      <div className="max-w-7xl mx-auto px-4 py-6 md:py-8">
        <header className="mb-6 flex flex-col gap-4">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-black text-white mb-1 tracking-tight">Painel Operacional</h1>
              <p className="text-[10px] text-gray-500 uppercase tracking-widest font-bold">
                Conectado em: <span className="text-emerald-500 font-mono">{state.selectedProject?.name || 'Aguardando Seleção'}</span>
              </p>
            </div>

            <div className="flex bg-gray-900/80 p-1.5 rounded-2xl border border-gray-800 w-full md:w-auto shadow-2xl">
              {['dashboard', 'backup', 'explorer', 'sql'].map((view) => (
                <button
                  key={view}
                  onClick={() => setState(prev => ({...prev, activeView: view as any}))}
                  className={`flex-1 md:flex-none px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${state.activeView === view ? 'bg-emerald-500 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
                >
                  {view === 'dashboard' ? 'Geral' : view === 'explorer' ? 'Tabelas' : view.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          <aside className="lg:col-span-1 space-y-4">
            <h2 className="text-[10px] font-black text-gray-600 uppercase tracking-[0.2em] px-2">Projetos Ativos</h2>
            <div className="space-y-2">
              {state.projects.map(p => (
                <ProjectCard 
                  key={p.id} 
                  project={p} 
                  isSelected={state.selectedProject?.id === p.id}
                  onClick={() => handleSelectProject(p)}
                />
              ))}
            </div>
          </aside>

          <section className="lg:col-span-3">
            {state.selectedProject ? (
              <div className="space-y-6">
                {state.activeView === 'dashboard' && (
                  <div className="space-y-6">
                    <div className="glass-card rounded-3xl p-6 md:p-10 border border-gray-800 shadow-2xl relative overflow-hidden">
                      <div className="flex flex-col md:flex-row justify-between items-start gap-8 mb-10">
                        <div className="flex-1">
                          <h2 className="text-4xl font-black text-white mb-3 tracking-tighter">{state.selectedProject.name}</h2>
                          <div className="flex flex-wrap gap-2">
                            <span className="text-[10px] font-mono text-emerald-400 bg-emerald-500/10 px-3 py-1 rounded-full border border-emerald-500/20">{state.selectedProject.id}</span>
                            <span className="text-[10px] font-mono text-blue-400 bg-blue-500/10 px-3 py-1 rounded-full border border-blue-500/20">{state.selectedProject.region}</span>
                          </div>
                        </div>
                        <div className="flex flex-col items-end gap-4 w-full md:w-auto">
                           <button 
                            onClick={runQuickBackup}
                            disabled={backupProgress.active}
                            className={`w-full md:w-auto bg-emerald-500 text-white font-black text-xs px-10 py-5 rounded-2xl shadow-2xl shadow-emerald-500/20 flex items-center justify-center gap-3 active:scale-95 transition-all ${backupProgress.active ? 'opacity-50' : 'hover:brightness-110'}`}
                           >
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                              </svg>
                              {backupProgress.active ? `FAZENDO BACKUP ${backupProgress.percent}%` : 'BAIXAR BACKUP AGORA'}
                           </button>
                        </div>
                      </div>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 mb-10">
